12	// StaleLockAge is the duration after which a lock is considered stale
13	// and can be forcibly broken. Default: 2 hours.
14	var StaleLockAge = 2 * time.Hour
15	
16	// WithLock acquires the file lock, runs fn, then releases the lock.
17	// For external backends, locking is delegated to the backend tool.
18	func (s *Store) WithLock(fn func() error) error {
19		if s.backend != nil {
20			return s.backend.WithLock(fn)
21		}
22		if err := s.acquireLock(); err != nil {
23			return err
24		}
25		defer s.releaseLock()
26		return fn()
27	}
28	
29	func (s *Store) acquireLock() error {
30		return acquireDirLock(s.Dir, s.LockDir, s.LockWait)
31	}
32	
33	// acquireDirLock is the file-lock primitive used by both Store and the
34	// standalone JSONLBackend. dir is the directory to ensure exists before the
35	// lock is taken; lockDir is the lock directory itself; wait bounds the spin.
36	func acquireDirLock(dir, lockDir string, wait time.Duration) error {
37		if err := os.MkdirAll(dir, 0o755); err != nil {
38			return fmt.Errorf("bead: lock dir: %w", err)
39		}
40	
41		deadline := time.Now().Add(wait)
42		for {
43			err := os.Mkdir(lockDir, 0o755)
44			if err == nil {
45				_ = os.WriteFile(filepath.Join(lockDir, "pid"),
46					[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644)
47				_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"),
48					[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644)
49				return nil
50			}
51	
52			if breakStaleLockDir(lockDir) {
53				continue
54			}
55	
56			if time.Now().After(deadline) {
57				owner := "unknown"
58				pidData, _ := os.ReadFile(filepath.Join(lockDir, "pid"))
59				if len(pidData) > 0 {
60					owner = strings.TrimSpace(string(pidData))
61				}
62				return fmt.Errorf("bead: lock timeout (owner pid: %s)", owner)
63			}
64			time.Sleep(50 * time.Millisecond)
65		}
66	}
67	
68	// breakStaleLock checks if the existing lock is stale (owner dead or too old)
69	// and breaks it if so. Returns true if lock was broken.
70	func (s *Store) breakStaleLock() bool {
71		return breakStaleLockDir(s.LockDir)
72	}
73	
74	func breakStaleLockDir(lockDir string) bool {
75		pidData, err := os.ReadFile(filepath.Join(lockDir, "pid"))
76		if err == nil {
77			pid, err := strconv.Atoi(strings.TrimSpace(string(pidData)))
78			if err == nil && pid > 0 && pid != os.Getpid() {
79				if !processAlive(pid) {
80					os.RemoveAll(lockDir)
81					return true
82				}
83			}
84		}
85	
86		acquiredData, err := os.ReadFile(filepath.Join(lockDir, "acquired_at"))
87		if err == nil {
88			acquired, err := time.Parse(time.RFC3339, strings.TrimSpace(string(acquiredData)))
89			if err == nil && time.Since(acquired) > StaleLockAge {
90				os.RemoveAll(lockDir)
91				return true
92			}
93		}
94	
95		return false
96	}
97	
98	func (s *Store) releaseLock() {
99		os.RemoveAll(s.LockDir)
100	}
