2112	//
2113	// The probe-common-ports heuristic that used to live here only worked for
2114	// the legacy plaintext http://127.0.0.1:8080 setup and never honored the
2115	// TLS default that's been in place since alpha13. Clients that skipped
2116	// the addr file would silently get a connection refused and tell the
2117	// user the server wasn't running when it was listening on 7743.
2118	func resolveServerURL(projectRoot string) string {
2119		if u := os.Getenv("DDX_SERVER_URL"); u != "" {
2120			return u
2121		}
2122		if u := serverpkg.ReadServerAddr(); u != "" {
2123			return rewriteBindAddrForClient(u)
2124		}
2125		return "https://127.0.0.1:7743"
2126	}
