2128	// rewriteBindAddrForClient converts a bind-address URL into a client-reachable
2129	// URL. 0.0.0.0 (and [::]) are valid listen addresses but not reachable as
2130	// client destinations on all platforms — substitute 127.0.0.1 so local HTTP
2131	// clients can always connect.
2132	func rewriteBindAddrForClient(u string) string {
2133		for _, bind := range []string{"//0.0.0.0:", "//[::]:", "//[::0]:"} {
2134			if idx := strings.Index(u, bind); idx >= 0 {
2135				return u[:idx] + "//127.0.0.1:" + u[idx+len(bind):]
2136			}
2137		}
2138		return u
2139	}

