29	func register(serverURL, projectPath string) {
30		body, err := json.Marshal(map[string]string{"path": projectPath})
31		if err != nil {
32			return
33		}
34	
35		client := &http.Client{
36			Timeout: 500 * time.Millisecond,
37			// Accept self-signed certs — the server uses an auto-generated cert.
38			Transport: &http.Transport{
39				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
40			},
41		}
42	
43		req, err := http.NewRequest(http.MethodPost, serverURL+"/api/projects/register", bytes.NewReader(body))
44		if err != nil {
45			return
46		}
47		req.Header.Set("Content-Type", "application/json")
48	
49		resp, err := client.Do(req)
50		if err != nil {
51			return
52		}
53		_ = resp.Body.Close()
54	}
